import{_ as s,c as t,a2 as n,o as e}from"./chunks/framework.C-Nz83Xi.js";const h=JSON.parse('{"title":"绝对质量","description":"","frontmatter":{},"headers":[],"relativePath":"atom.md","filePath":"atom.md","lastUpdated":null}'),o={name:"atom.md"};function r(l,a,p,i,c,d){return e(),t("div",null,a[0]||(a[0]=[n(`<h1 id="绝对质量" tabindex="-1">绝对质量 <a class="header-anchor" href="#绝对质量" aria-label="Permalink to &quot;绝对质量&quot;">​</a></h1><p>一般原子的直径在10⁻10 m（Å）数量级，质量在10⁻²⁷kg这个数量级 最精密的天平（德国生产的“4108 型”天平）的精度10⁻11²⁷-11Kg（0.01微克） 原子的精确质量可用<strong>质谱仪</strong>[[MS]]测量</p><h1 id="相对质量" tabindex="-1">相对质量 <a class="header-anchor" href="#相对质量" aria-label="Permalink to &quot;相对质量&quot;">​</a></h1><p>以一种碳原子(原子核内有6个质子和6个中子的一种碳原子即C12)的质量的1/12(约1.667×10⁻²⁷kg)作为标准，其它原子的质量跟它的比值，就是这种原子的相对原子质量。 国际单位：<strong>道尔顿</strong>，<strong>Da</strong>（Dalton），等于一个碳原子(C12)质量的十二分之一，约为1.66×10⁻²⁷克 原子质量单位，amu=atomic mass unit，1amu=1Da</p><h1 id="常用的质量形式" tabindex="-1">常用的质量形式 <a class="header-anchor" href="#常用的质量形式" aria-label="Permalink to &quot;常用的质量形式&quot;">​</a></h1><p>规定的角度： 1、相对原子质量（元素周期表中的数值） <strong>一种元素的所有天然同位素的重量的天然[[丰度]]加权平均值</strong> 2、相对分子质量：化学式中各原子的相对原子质量加和所得</p><p>检测的角度： 3、精确分子量（Exact Mass）：组成化合物中的各种元素在自然界有不同的丰度，精确分子量是以丰度最高的分子量进行加和所得。 4、摩尔分子量（Mol.Wt.）：是化合物中的各种元素在自然界中的同位素的丰度取平均值进行加和而得。理论上等于相对原子质量的加和 以HBr为例，在<strong>Chemdraw软件中</strong>获得的数据：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chemical Formula: BrH</span></span>
<span class="line"><span>Exact Mass: 79.93</span></span>
<span class="line"><span>Molecular Weight: 80.91</span></span>
<span class="line"><span>m/z: 79.93 (100.0%), 81.92 (97.3%)</span></span>
<span class="line"><span>Elemental Analysis: Br, 98.75; H, 1.25</span></span></code></pre></div><p>79.9的Br占比为100%，81.9的Br占比为97.3%，那Br的<strong>摩尔分子量</strong>的加权平均值为 79.9；H只有一种m/z值1.01，则HBr的摩尔分子量的加权平均值为 80.91 m/z代表质谱测得的不同同位素的分子质量，则<strong>精确分子量</strong>为丰度最高的79.93</p>`,9)]))}const g=s(o,[["render",r]]);export{h as __pageData,g as default};
